option.value:
-- Fix vehicles timestamp defaults for Supabase/PostgREST inserts
-- Run this in Supabase SQL Editor for each environment.

BEGIN;

-- Backfill existing rows if any were inserted before this fix.
UPDATE public.vehicles
SET created_at = COALESCE(created_at, NOW()),
    updated_at = COALESCE(updated_at, NOW())
WHERE created_at IS NULL OR updated_at IS NULL;

-- Ensure inserts do not fail when timestamp fields are omitted.
ALTER TABLE public.vehicles
  ALTER COLUMN created_at SET DEFAULT NOW(),
  ALTER COLUMN updated_at SET DEFAULT NOW();

-- Keep created_at mandatory while preserving automatic default behavior.
ALTER TABLE public.vehicles
  ALTER COLUMN created_at SET NOT NULL;

COMMIT;

import 'package:supabase_flutter/supabase_flutter.dart';

class SupabaseService {
  static final SupabaseService _instance = SupabaseService._internal();
  factory SupabaseService() => _instance;
  SupabaseService._internal();

  SupabaseClient get client => Supabase.instance.client;

  // Get current user
  User? get currentUser => client.auth.currentUser;

  // Get current session
  Session? get currentSession => client.auth.currentSession;

  // Check if user is logged in
  bool get isLoggedIn => currentUser != null;

  // Sign in with email and password
  Future<AuthResponse> signInWithEmail({
    required String email,
    required String password,
  }) async {
    return await client.auth.signInWithPassword(
      email: email,
      password: password,
    );
  }

  // Sign up with email and password
  Future<AuthResponse> signUpWithEmail({
    required String email,
    required String password,
    Map<String, dynamic>? data,
  }) async {
    return await client.auth.signUp(
      email: email,
      password: password,
      data: data,
    );
  }

  // Sign in with Google
  Future<bool> signInWithGoogle() async {
    try {
      await client.auth.signInWithOAuth(
        OAuthProvider.google,
        redirectTo: 'io.supabase.servio://login-callback/',
      );
      return true;
    } catch (e) {
      print('Error signing in with Google: $e');
      return false;
    }
  }

  // Sign in with Facebook
  Future<bool> signInWithFacebook() async {
    try {
      await client.auth.signInWithOAuth(
        OAuthProvider.facebook,
        redirectTo: 'io.supabase.servio://login-callback/',
      );
      return true;
    } catch (e) {
      print('Error signing in with Facebook: $e');
      return false;
    }
  }

  // Sign out
  Future<void> signOut() async {
    await client.auth.signOut();
  }

  // Reset password
  Future<void> resetPasswordForEmail(String email) async {
    await client.auth.resetPasswordForEmail(email);
  }

  // Listen to auth state changes
  Stream<AuthState> get authStateChanges => client.auth.onAuthStateChange;

  // Update user profile
  Future<UserResponse> updateUserProfile({Map<String, dynamic>? data}) async {
    return await client.auth.updateUser(UserAttributes(data: data));
  }

  // Fetch full user profile from profiles table
  Future<Map<String, dynamic>?> getUserProfile(String userId) async {
    try {
      final response = await client
          .from('profiles')
          .select()
          .eq('id', userId)
          .maybeSingle();
      return response;
    } catch (e) {
      print('Error fetching user profile: $e');
      return null;
    }
  }
}

import 'package:supabase_flutter/supabase_flutter.dart';

class SupabaseService {
  static final SupabaseService _instance = SupabaseService._internal();
  factory SupabaseService() => _instance;
  SupabaseService._internal();

  SupabaseClient get client => Supabase.instance.client;

  // Get current user
  User? get currentUser => client.auth.currentUser;

  // Get current session
  Session? get currentSession => client.auth.currentSession;

  // Check if user is logged in
  bool get isLoggedIn => currentUser != null;

  // Sign in with email and password
  Future<AuthResponse> signInWithEmail({
    required String email,
    required String password,
  }) async {
    return await client.auth.signInWithPassword(
      email: email,
      password: password,
    );
  }

  // Sign up with email and password
  Future<AuthResponse> signUpWithEmail({
    required String email,
    required String password,
    Map<String, dynamic>? data,
  }) async {
    return await client.auth.signUp(
      email: email,
      password: password,
      data: data,
    );
  }

  // Request email OTP via /auth/v1/otp (higher default rate limit).
  Future<void> requestSignupOtp({
    required String email,
    Map<String, dynamic>? data,
  }) async {
    await client.auth.signInWithOtp(
      email: email,
      shouldCreateUser: true,
      data: data,
    );
  }

  Future<AuthResponse> verifyEmailOtp({
    required String email,
    required String otp,
  }) async {
    return await client.auth.verifyOTP(
      type: OtpType.email,
      email: email,
      token: otp,
    );
  }

  Future<void> resendEmailOtp({required String email}) async {
    await client.auth.resend(type: OtpType.email, email: email);
  }

  Future<UserResponse> setPassword(String password) async {
    return await client.auth.updateUser(UserAttributes(password: password));
  }

  // Sign in with Google
  Future<bool> signInWithGoogle() async {
    try {
      await client.auth.signInWithOAuth(
        OAuthProvider.google,
        redirectTo: 'io.supabase.servio://login-callback/',
      );
      return true;
    } catch (e) {
      print('Error signing in with Google: $e');
      return false;
    }
  }

  // Sign in with Facebook
  Future<bool> signInWithFacebook() async {
    try {
      await client.auth.signInWithOAuth(
        OAuthProvider.facebook,
        redirectTo: 'io.supabase.servio://login-callback/',
      );
      return true;
    } catch (e) {
      print('Error signing in with Facebook: $e');
      return false;
    }
  }

  // Sign out
  Future<void> signOut() async {
    await client.auth.signOut();
  }

  // Reset password
  Future<void> resetPasswordForEmail(String email) async {
    await client.auth.resetPasswordForEmail(email);
  }

  // Listen to auth state changes
  Stream<AuthState> get authStateChanges => client.auth.onAuthStateChange;

  // Update user profile
  Future<UserResponse> updateUserProfile({Map<String, dynamic>? data}) async {
    return await client.auth.updateUser(UserAttributes(data: data));
  }

  // Fetch full user profile from profiles table
  Future<Map<String, dynamic>?> getUserProfile(String userId) async {
    try {
      final response = await client
          .from('profiles')
          .select()
          .eq('id', userId)
          .maybeSingle();
      return response;
    } catch (e) {
      print('Error fetching user profile: $e');
      return null;
    }
  }
}

import 'dart:async';

import 'package:flutter/material.dart';
import 'package:flutter/services.dart';
import 'package:go_router/go_router.dart';
import 'package:google_fonts/google_fonts.dart';
import 'package:gotrue/gotrue.dart' show OtpType;
import 'package:supabase_flutter/supabase_flutter.dart';

import '../../core/services/supabase_service.dart';
import 'signup_widgets.dart';

class SignUpOtpScreen extends StatefulWidget {
  final Map<String, dynamic>? extras;

  const SignUpOtpScreen({super.key, this.extras});

  @override
  State<SignUpOtpScreen> createState() => _SignUpOtpScreenState();
}

class _SignUpOtpScreenState extends State<SignUpOtpScreen> {
  static const int _otpLength = 4;

  final _supabaseService = SupabaseService();
  final List<TextEditingController> _otpControllers = List.generate(
    _otpLength,
    (_) => TextEditingController(),
  );
  final List<FocusNode> _focusNodes = List.generate(
    _otpLength,
    (_) => FocusNode(),
  );

  bool _isLoading = false;
  int _resendCountdown = 60;
  Timer? _timer;
  late String _email;

  @override
  void initState() {
    super.initState();
    _email = (widget.extras?['email'] as String?) ?? '';
    _startCountdown();
  }

  @override
  void dispose() {
    _timer?.cancel();
    for (final c in _otpControllers) {
      c.dispose();
    }
    for (final f in _focusNodes) {
      f.dispose();
    }
    super.dispose();
  }

  void _startCountdown() {
    _resendCountdown = 60;
    _timer?.cancel();
    _timer = Timer.periodic(const Duration(seconds: 1), (t) {
      if (!mounted) {
        t.cancel();
        return;
      }
      setState(() {
        if (_resendCountdown > 0) {
          _resendCountdown--;
        } else {
          t.cancel();
        }
      });
    });
  }

  String get _otpCode => _otpControllers.map((c) => c.text).join();

  Future<void> _handleVerify() async {
    if (_email.isEmpty) {
      _showSnackBar('Email is missing. Please go back and try again.');
      return;
    }

    final code = _otpCode;
    if (code.length < _otpLength) {
      _showSnackBar('Please enter the full $_otpLength-digit code.');
      return;
    }

    setState(() => _isLoading = true);

    try {
      await _supabaseService.client.auth.verifyOTP(
        type: OtpType.signup,
        email: _email,
        token: code,
      );

      if (!mounted) return;

      _showSnackBar('Email verified!', isError: false);
      context.go('/signup/vehicle', extra: widget.extras);
    } catch (e) {
      if (mounted) {
        String msg = 'Invalid code. Please try again.';
        final s = e.toString();
        if (s.contains('Token has expired')) {
          msg = 'Code has expired. Please request a new one.';
        }
        _showSnackBar(msg);
      }
    } finally {
      if (mounted) setState(() => _isLoading = false);
    }
  }

  Future<void> _handleResend() async {
    if (_resendCountdown > 0) return;
    if (_email.isEmpty) {
      _showSnackBar('Email is missing. Please go back and try again.');
      return;
    }

    try {
      await _supabaseService.client.auth.resend(
        type: OtpType.signup,
        email: _email,
      );
      if (mounted) {
        _showSnackBar('Verification code resent!', isError: false);
        _startCountdown();
      }
    } catch (e) {
      if (mounted) {
        _showSnackBar('Failed to resend code. Please try again.');
      }
    }
  }

  void _showSnackBar(String message, {bool isError = true}) {
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text(message),
        backgroundColor: isError ? Colors.red : Colors.green,
        duration: const Duration(seconds: 3),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final maskedEmail = _email.isNotEmpty
        ? _email.replaceRange(
            1,
            _email.indexOf('@') > 1 ? _email.indexOf('@') - 1 : 1,
            '***',
          )
        : 'your email';

    return SignUpScaffold(
      children: [
        // Header
        SignUpHeader(
          step: 2,
          title: 'Check your inbox',
          subtitle:
              'We sent a $_otpLength-digit code to $maskedEmail. Enter it below to verify your account.',
          onBack: () {
            if (Navigator.canPop(context)) {
              Navigator.pop(context);
            } else {
              context.go('/signup', extra: widget.extras);
            }
          },
        ),
        const SizedBox(height: 8),

        // OTP Input + Resend
        Expanded(
          child: Padding(
            padding: const EdgeInsets.symmetric(vertical: 24),
            child: Column(
              children: [
                // OTP digit boxes
                SizedBox(
                  width: 320,
                  height: 64,
                  child: Row(
                    children: List.generate(_otpLength, (i) {
                      return Expanded(
                        child: Container(
                          margin: EdgeInsets.only(left: i > 0 ? 8 : 0),
                          decoration: BoxDecoration(
                            color: const Color(0xFFFFE7DF),
                            borderRadius: BorderRadius.circular(8),
                            border: Border.all(color: Colors.white),
                          ),
                          child: TextField(
                            controller: _otpControllers[i],
                            focusNode: _focusNodes[i],
                            keyboardType: TextInputType.number,
                            textAlign: TextAlign.center,
                            maxLength: 1,
                            inputFormatters: [
                              FilteringTextInputFormatter.digitsOnly,
                            ],
                            style: GoogleFonts.instrumentSans(
                              fontSize: 24,
                              fontWeight: FontWeight.w600,
                              color: Colors.black,
                            ),
                            decoration: const InputDecoration(
                              counterText: '',
                              border: InputBorder.none,
                            ),
                            onChanged: (value) {
                              if (value.isNotEmpty && i < _otpLength - 1) {
                                _focusNodes[i + 1].requestFocus();
                              } else if (value.isEmpty && i > 0) {
                                _focusNodes[i - 1].requestFocus();
                              }
                              // Auto-submit on last digit
                              if (value.isNotEmpty &&
                                  i == _otpLength - 1 &&
                                  _otpCode.length == _otpLength) {
                                _handleVerify();
                              }
                            },
                          ),
                        ),
                      );
                    }),
                  ),
                ),
                const SizedBox(height: 32),

                // Resend text
                GestureDetector(
                  onTap: _resendCountdown == 0 ? _handleResend : null,
                  child: RichText(
                    text: TextSpan(
                      style: GoogleFonts.instrumentSans(
                        fontSize: 12,
                        fontWeight: FontWeight.w400,
                        color: Colors.black,
                        height: 16 / 12,
                      ),
                      children: [
                        const TextSpan(text: "Didn't get the code? "),
                        TextSpan(
                          text: _resendCountdown > 0
                              ? 'Resend it (${_resendCountdown.toString().padLeft(2, '0')}s)'
                              : 'Resend it',
                          style: GoogleFonts.instrumentSans(
                            fontSize: 12,
                            fontWeight: FontWeight.w400,
                            color: _resendCountdown > 0
                                ? const Color(0xFF8A8A8A)
                                : const Color(0xFFFF5D2E),
                            decoration: TextDecoration.underline,
                            height: 16 / 12,
                          ),
                        ),
                      ],
                    ),
                  ),
                ),

                const SizedBox(height: 24),
              ],
            ),
          ),
        ),

        // Verify button
        Padding(
          padding: const EdgeInsets.fromLTRB(16, 16, 16, 16),
          child: SignUpPrimaryButton(
            label: 'Verify & Continue',
            onTap: _handleVerify,
            isLoading: _isLoading,
          ),
        ),
      ],
    );
  }
}

import 'dart:async';

import 'package:flutter/material.dart';
import 'package:flutter/services.dart';
import 'package:go_router/go_router.dart';
import 'package:google_fonts/google_fonts.dart';

import '../../core/services/supabase_service.dart';
import 'signup_widgets.dart';

class SignUpOtpScreen extends StatefulWidget {
  final Map<String, dynamic>? extras;

  const SignUpOtpScreen({super.key, this.extras});

  @override
  State<SignUpOtpScreen> createState() => _SignUpOtpScreenState();
}

class _SignUpOtpScreenState extends State<SignUpOtpScreen> {
  static const int _otpLength = 6;

  final _supabaseService = SupabaseService();
  final List<TextEditingController> _otpControllers = List.generate(
    _otpLength,
    (_) => TextEditingController(),
  );
  final List<FocusNode> _focusNodes = List.generate(
    _otpLength,
    (_) => FocusNode(),
  );

  bool _isLoading = false;
  int _resendCountdown = 60;
  Timer? _timer;
  late String _email;
  late String _password;

  @override
  void initState() {
    super.initState();
    _email = (widget.extras?['email'] as String?) ?? '';
    _password = (widget.extras?['password'] as String?) ?? '';
    _startCountdown();
  }

  @override
  void dispose() {
    _timer?.cancel();
    for (final c in _otpControllers) {
      c.dispose();
    }
    for (final f in _focusNodes) {
      f.dispose();
    }
    super.dispose();
  }

  void _startCountdown() {
    _resendCountdown = 60;
    _timer?.cancel();
    _timer = Timer.periodic(const Duration(seconds: 1), (t) {
      if (!mounted) {
        t.cancel();
        return;
      }
      setState(() {
        if (_resendCountdown > 0) {
          _resendCountdown--;
        } else {
          t.cancel();
        }
      });
    });
  }

  String get _otpCode => _otpControllers.map((c) => c.text).join();

  Future<void> _handleVerify() async {
    if (_email.isEmpty) {
      _showSnackBar('Email is missing. Please go back and try again.');
      return;
    }

    final code = _otpCode;
    if (code.length < _otpLength) {
      _showSnackBar('Please enter the full $_otpLength-digit code.');
      return;
    }

    setState(() => _isLoading = true);

    try {
      final response = await _supabaseService.verifyEmailOtp(
        email: _email,
        otp: code,
      );

      // OTP login creates/opens a session; set password so future login can use email+password.
      if (response.user != null && _password.isNotEmpty) {
        await _supabaseService.setPassword(_password);

        final phone = (widget.extras?['phone'] as String?)?.trim() ?? '';
        if (phone.isNotEmpty) {
          try {
            await _supabaseService.client
                .from('profiles')
                .update({'phone': phone})
                .eq('id', response.user!.id);
          } catch (e) {
            debugPrint('Error updating phone in profile: $e');
          }
        }
      }

      if (!mounted) return;

      _showSnackBar('Email verified!', isError: false);
      context.go('/signup/vehicle', extra: widget.extras);
    } catch (e) {
      if (mounted) {
        String msg = 'Invalid code. Please try again.';
        final s = e.toString();
        if (s.contains('Token has expired')) {
          msg = 'Code has expired. Please request a new one.';
        }
        _showSnackBar(msg);
      }
    } finally {
      if (mounted) setState(() => _isLoading = false);
    }
  }

  Future<void> _handleResend() async {
    if (_resendCountdown > 0) return;
    if (_email.isEmpty) {
      _showSnackBar('Email is missing. Please go back and try again.');
      return;
    }

    try {
      await _supabaseService.resendEmailOtp(email: _email);
      if (mounted) {
        _showSnackBar('Verification code resent!', isError: false);
        _startCountdown();
      }
    } catch (e) {
      if (mounted) {
        _showSnackBar('Failed to resend code. Please try again.');
      }
    }
  }

  void _showSnackBar(String message, {bool isError = true}) {
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text(message),
        backgroundColor: isError ? Colors.red : Colors.green,
        duration: const Duration(seconds: 3),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final maskedEmail = _email.isNotEmpty
        ? _email.replaceRange(
            1,
            _email.indexOf('@') > 1 ? _email.indexOf('@') - 1 : 1,
            '***',
          )
        : 'your email';

    return SignUpScaffold(
      children: [
        // Header
        SignUpHeader(
          step: 2,
          title: 'Check your inbox',
          subtitle:
              'We sent a $_otpLength-digit code to $maskedEmail. Enter it below to verify your account.',
          onBack: () {
            if (Navigator.canPop(context)) {
              Navigator.pop(context);
            } else {
              context.go('/signup', extra: widget.extras);
            }
          },
        ),
        const SizedBox(height: 8),

        // OTP Input + Resend
        Expanded(
          child: Padding(
            padding: const EdgeInsets.symmetric(vertical: 24),
            child: Column(
              children: [
                // OTP digit boxes
                SizedBox(
                  width: 320,
                  height: 64,
                  child: Row(
                    children: List.generate(_otpLength, (i) {
                      return Expanded(
                        child: Container(
                          margin: EdgeInsets.only(left: i > 0 ? 8 : 0),
                          decoration: BoxDecoration(
                            color: const Color(0xFFFFE7DF),
                            borderRadius: BorderRadius.circular(8),
                            border: Border.all(color: Colors.white),
                          ),
                          child: TextField(
                            controller: _otpControllers[i],
                            focusNode: _focusNodes[i],
                            keyboardType: TextInputType.number,
                            textAlign: TextAlign.center,
                            maxLength: 1,
                            inputFormatters: [
                              FilteringTextInputFormatter.digitsOnly,
                            ],
                            style: GoogleFonts.instrumentSans(
                              fontSize: 24,
                              fontWeight: FontWeight.w600,
                              color: Colors.black,
                            ),
                            decoration: const InputDecoration(
                              counterText: '',
                              border: InputBorder.none,
                            ),
                            onChanged: (value) {
                              if (value.isNotEmpty && i < _otpLength - 1) {
                                _focusNodes[i + 1].requestFocus();
                              } else if (value.isEmpty && i > 0) {
                                _focusNodes[i - 1].requestFocus();
                              }
                              // Auto-submit on last digit
                              if (value.isNotEmpty &&
                                  i == _otpLength - 1 &&
                                  _otpCode.length == _otpLength) {
                                _handleVerify();
                              }
                            },
                          ),
                        ),
                      );
                    }),
                  ),
                ),
                const SizedBox(height: 32),

                // Resend text
                GestureDetector(
                  onTap: _resendCountdown == 0 ? _handleResend : null,
                  child: RichText(
                    text: TextSpan(
                      style: GoogleFonts.instrumentSans(
                        fontSize: 12,
                        fontWeight: FontWeight.w400,
                        color: Colors.black,
                        height: 16 / 12,
                      ),
                      children: [
                        const TextSpan(text: "Didn't get the code? "),
                        TextSpan(
                          text: _resendCountdown > 0
                              ? 'Resend it (${_resendCountdown.toString().padLeft(2, '0')}s)'
                              : 'Resend it',
                          style: GoogleFonts.instrumentSans(
                            fontSize: 12,
                            fontWeight: FontWeight.w400,
                            color: _resendCountdown > 0
                                ? const Color(0xFF8A8A8A)
                                : const Color(0xFFFF5D2E),
                            decoration: TextDecoration.underline,
                            height: 16 / 12,
                          ),
                        ),
                      ],
                    ),
                  ),
                ),

                const SizedBox(height: 24),
              ],
            ),
          ),
        ),

        // Verify button
        Padding(
          padding: const EdgeInsets.fromLTRB(16, 16, 16, 16),
          child: SignUpPrimaryButton(
            label: 'Verify & Continue',
            onTap: _handleVerify,
            isLoading: _isLoading,
          ),
        ),
      ],
    );
  }
}

import 'package:flutter/material.dart';
import 'package:go_router/go_router.dart';
import 'package:google_fonts/google_fonts.dart';

import '../../core/services/supabase_service.dart';
import '../../core/utils/email_validator.dart';
import 'signup_widgets.dart';

class SignUpStep1Screen extends StatefulWidget {
  final Map<String, dynamic>? extras;

  const SignUpStep1Screen({super.key, this.extras});

  @override
  State<SignUpStep1Screen> createState() => _SignUpStep1ScreenState();
}

class _SignUpStep1ScreenState extends State<SignUpStep1Screen> {
  final _formKey = GlobalKey<FormState>();
  final _nameController = TextEditingController();
  final _emailController = TextEditingController();
  final _phoneController = TextEditingController();
  final _passwordController = TextEditingController();
  final _supabaseService = SupabaseService();

  bool _obscurePassword = true;
  bool _isLoading = false;

  @override
  void initState() {
    super.initState();
    final extras = widget.extras;
    if (extras == null) return;

    _nameController.text = (extras['name'] as String?) ?? '';
    _emailController.text = (extras['email'] as String?) ?? '';
    _phoneController.text = (extras['phone'] as String?) ?? '';
  }

  @override
  void dispose() {
    _nameController.dispose();
    _emailController.dispose();
    _phoneController.dispose();
    _passwordController.dispose();
    super.dispose();
  }

  Future<void> _handleCreateAccount() async {
    if (!(_formKey.currentState?.validate() ?? false)) return;
    FocusScope.of(context).unfocus();

    setState(() => _isLoading = true);

    try {
      final email = _emailController.text.trim();
      final password = _passwordController.text;
      final name = _nameController.text.trim();
      final phone = _phoneController.text.trim();

      // Start sign-up from a clean auth state to avoid carrying a previous user.
      if (_supabaseService.currentSession != null) {
        await _supabaseService.signOut();
      }

      // Sign up with Supabase Auth
      final response = await _supabaseService.signUpWithEmail(
        email: email,
        password: password,
        data: {'full_name': name, 'display_name': name},
      );

      if (!mounted) return;

      if (response.user != null) {
        // Update phone in profiles table
        if (phone.isNotEmpty) {
          try {
            await _supabaseService.client
                .from('profiles')
                .update({'phone': phone})
                .eq('id', response.user!.id);
          } catch (e) {
            debugPrint('Error updating phone in profile: $e');
            // Non-blocking — profile trigger may not have fired yet
          }
        }

        _showSnackBar(
          'Account created! Please verify your email.',
          isError: false,
        );

        // Navigate to OTP / email verification screen
        if (mounted) {
          context.go(
            '/signup/otp',
            extra: {
              ...?widget.extras,
              'email': email,
              'name': name,
              'phone': phone,
            },
          );
        }
      } else if (mounted) {
        _showSnackBar('Sign up failed. Please try again.');
      }
    } catch (e) {
      if (mounted) {
        String errorMessage = 'Sign up failed. Please try again.';
        final errorStr = e.toString();

        if (errorStr.contains('User already registered')) {
          errorMessage = 'An account with this email already exists.';
        } else if (errorStr.contains('Password should be at least')) {
          errorMessage = 'Password must be at least 8 characters.';
        } else if (errorStr.contains('Network') ||
            errorStr.contains('SocketException') ||
            errorStr.contains('Failed host lookup') ||
            errorStr.contains('ClientException') ||
            errorStr.contains('AuthRetryableFetchException')) {
          errorMessage =
              'Unable to connect to the server. Please check your internet connection.';
        } else if (errorStr.contains('rate limit') ||
            errorStr.contains('429')) {
          errorMessage =
              'Too many attempts. Please wait a moment and try again.';
        }

        _showSnackBar(errorMessage);
      }
    } finally {
      if (mounted) setState(() => _isLoading = false);
    }
  }

  void _showSnackBar(String message, {bool isError = true}) {
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text(message),
        backgroundColor: isError ? Colors.red : Colors.green,
        duration: const Duration(seconds: 3),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return SignUpScaffold(
      children: [
        // Header
        SignUpHeader(
          step: 1,
          title: "Let's get you on the road",
          subtitle:
              "Create your account to easily book services and track your vehicle's health.",
          onBack: () {
            if (Navigator.canPop(context)) {
              Navigator.pop(context);
            } else {
              context.go('/signin');
            }
          },
        ),
        const SizedBox(height: 8),

        // Form
        Expanded(
          child: SingleChildScrollView(
            padding: const EdgeInsets.fromLTRB(16, 16, 16, 0),
            child: Form(
              key: _formKey,
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  const SignUpLabel('Full Name:'),
                  const SizedBox(height: 8),
                  SignUpInputField(
                    controller: _nameController,
                    hint: 'Chamira Fernando',
                    validator: (v) {
                      if (v == null || v.trim().isEmpty) {
                        return 'Please enter your name';
                      }
                      return null;
                    },
                  ),
                  const SizedBox(height: 16),

                  const SignUpLabel('Email Address:'),
                  const SizedBox(height: 8),
                  SignUpInputField(
                    controller: _emailController,
                    hint: 'name@example.com',
                    keyboardType: TextInputType.emailAddress,
                    validator: (v) {
                      if (v == null || v.trim().isEmpty) {
                        return 'Please enter your email';
                      }
                      if (!EmailValidator.isValid(v)) {
                        return 'Please enter a valid email';
                      }
                      return null;
                    },
                  ),
                  const SizedBox(height: 16),

                  const SignUpLabel('Phone Number:'),
                  const SizedBox(height: 8),
                  SignUpInputField(
                    controller: _phoneController,
                    hint: '07X XXX XXXX',
                    keyboardType: TextInputType.phone,
                    validator: (v) {
                      if (v == null || v.trim().isEmpty) {
                        return 'Please enter your phone number';
                      }

                      // Remove +, spaces, and dashes for length validation
                      final digitsOnly = v.replaceAll(RegExp(r'[\+\s\-]'), '');
                      if (digitsOnly.length < 10) {
                        return 'Phone number must have at least 10 digits';
                      }
                      return null;
                    },
                  ),
                  const SizedBox(height: 8),
                  const SignUpHelperText(
                    "We'll only use this to send you service updates and urgent alerts.",
                  ),
                  const SizedBox(height: 16),

                  const SignUpLabel('Password:'),
                  const SizedBox(height: 8),
                  SignUpPasswordField(
                    controller: _passwordController,
                    obscure: _obscurePassword,
                    onToggle: () =>
                        setState(() => _obscurePassword = !_obscurePassword),
                    validator: (v) {
                      if (v == null || v.isEmpty) {
                        return 'Please enter a password';
                      }
                      if (v.length < 8) {
                        return 'Minimum 8 characters';
                      }
                      return null;
                    },
                  ),
                  const SizedBox(height: 8),
                  const SignUpHelperText('Minimum 8 characters.'),
                  const SizedBox(height: 24),

                  // Already have account link
                  Center(
                    child: GestureDetector(
                      onTap: () => context.go('/signin'),
                      child: Text(
                        'Already have an account? Sign In',
                        style: GoogleFonts.instrumentSans(
                          fontSize: 14,
                          fontWeight: FontWeight.w500,
                          color: Colors.black.withValues(alpha: 0.7),
                          height: 22 / 14,
                        ),
                      ),
                    ),
                  ),
                ],
              ),
            ),
          ),
        ),

        // Button
        Padding(
          padding: const EdgeInsets.fromLTRB(16, 16, 16, 16),
          child: SignUpPrimaryButton(
            label: 'Create Account',
            onTap: _handleCreateAccount,
            isLoading: _isLoading,
          ),
        ),
      ],
    );
  }
}

import 'package:flutter/material.dart';
import 'package:go_router/go_router.dart';
import 'package:google_fonts/google_fonts.dart';

import '../../core/services/supabase_service.dart';
import '../../core/utils/email_validator.dart';
import 'signup_widgets.dart';

class SignUpStep1Screen extends StatefulWidget {
  final Map<String, dynamic>? extras;

  const SignUpStep1Screen({super.key, this.extras});

  @override
  State<SignUpStep1Screen> createState() => _SignUpStep1ScreenState();
}

class _SignUpStep1ScreenState extends State<SignUpStep1Screen> {
  final _formKey = GlobalKey<FormState>();
  final _nameController = TextEditingController();
  final _emailController = TextEditingController();
  final _phoneController = TextEditingController();
  final _passwordController = TextEditingController();
  final _supabaseService = SupabaseService();

  bool _obscurePassword = true;
  bool _isLoading = false;

  @override
  void initState() {
    super.initState();
    final extras = widget.extras;
    if (extras == null) return;

    _nameController.text = (extras['name'] as String?) ?? '';
    _emailController.text = (extras['email'] as String?) ?? '';
    _phoneController.text = (extras['phone'] as String?) ?? '';
  }

  @override
  void dispose() {
    _nameController.dispose();
    _emailController.dispose();
    _phoneController.dispose();
    _passwordController.dispose();
    super.dispose();
  }

  Future<void> _handleCreateAccount() async {
    if (!(_formKey.currentState?.validate() ?? false)) return;
    FocusScope.of(context).unfocus();

    setState(() => _isLoading = true);

    try {
      final email = _emailController.text.trim();
      final password = _passwordController.text;
      final name = _nameController.text.trim();
      final phone = _phoneController.text.trim();

      // Start sign-up from a clean auth state to avoid carrying a previous user.
      if (_supabaseService.currentSession != null) {
        await _supabaseService.signOut();
      }

      // Use /auth/v1/otp instead of /auth/v1/signup to avoid strict email caps.
      await _supabaseService.requestSignupOtp(
        email: email,
        data: {
          'full_name': name,
          'display_name': name,
          'phone': phone,
          'signup_flow': 'otp',
        },
      );

      if (!mounted) return;

      _showSnackBar(
        'Verification code sent. Please check your email.',
        isError: false,
      );

      context.go(
        '/signup/otp',
        extra: {
          ...?widget.extras,
          'email': email,
          'name': name,
          'phone': phone,
          'password': password,
        },
      );
    } catch (e) {
      if (mounted) {
        String errorMessage = 'Sign up failed. Please try again.';
        final errorStr = e.toString();

        if (errorStr.contains('User already registered')) {
          errorMessage = 'An account with this email already exists.';
        } else if (errorStr.contains('For security purposes, you can only request this after')) {
          errorMessage = 'Please wait 60 seconds before requesting a new code.';
        } else if (errorStr.contains('Network') ||
            errorStr.contains('SocketException') ||
            errorStr.contains('Failed host lookup') ||
            errorStr.contains('ClientException') ||
            errorStr.contains('AuthRetryableFetchException')) {
          errorMessage =
              'Unable to connect to the server. Please check your internet connection.';
        } else if (errorStr.contains('rate limit') ||
            errorStr.contains('429')) {
          errorMessage =
              'Too many attempts. Please wait a moment and try again.';
        }

        _showSnackBar(errorMessage);
      }
    } finally {
      if (mounted) setState(() => _isLoading = false);
    }
  }

  void _showSnackBar(String message, {bool isError = true}) {
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text(message),
        backgroundColor: isError ? Colors.red : Colors.green,
        duration: const Duration(seconds: 3),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return SignUpScaffold(
      children: [
        // Header
        SignUpHeader(
          step: 1,
          title: "Let's get you on the road",
          subtitle:
              "Create your account to easily book services and track your vehicle's health.",
          onBack: () {
            if (Navigator.canPop(context)) {
              Navigator.pop(context);
            } else {
              context.go('/signin');
            }
          },
        ),
        const SizedBox(height: 8),

        // Form
        Expanded(
          child: SingleChildScrollView(
            padding: const EdgeInsets.fromLTRB(16, 16, 16, 0),
            child: Form(
              key: _formKey,
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  const SignUpLabel('Full Name:'),
                  const SizedBox(height: 8),
                  SignUpInputField(
                    controller: _nameController,
                    hint: 'Chamira Fernando',
                    validator: (v) {
                      if (v == null || v.trim().isEmpty) {
                        return 'Please enter your name';
                      }
                      return null;
                    },
                  ),
                  const SizedBox(height: 16),

                  const SignUpLabel('Email Address:'),
                  const SizedBox(height: 8),
                  SignUpInputField(
                    controller: _emailController,
                    hint: 'name@example.com',
                    keyboardType: TextInputType.emailAddress,
                    validator: (v) {
                      if (v == null || v.trim().isEmpty) {
                        return 'Please enter your email';
                      }
                      if (!EmailValidator.isValid(v)) {
                        return 'Please enter a valid email';
                      }
                      return null;
                    },
                  ),
                  const SizedBox(height: 16),

                  const SignUpLabel('Phone Number:'),
                  const SizedBox(height: 8),
                  SignUpInputField(
                    controller: _phoneController,
                    hint: '07X XXX XXXX',
                    keyboardType: TextInputType.phone,
                    validator: (v) {
                      if (v == null || v.trim().isEmpty) {
                        return 'Please enter your phone number';
                      }

                      // Remove +, spaces, and dashes for length validation
                      final digitsOnly = v.replaceAll(RegExp(r'[\+\s\-]'), '');
                      if (digitsOnly.length < 10) {
                        return 'Phone number must have at least 10 digits';
                      }
                      return null;
                    },
                  ),
                  const SizedBox(height: 8),
                  const SignUpHelperText(
                    "We'll only use this to send you service updates and urgent alerts.",
                  ),
                  const SizedBox(height: 16),

                  const SignUpLabel('Password:'),
                  const SizedBox(height: 8),
                  SignUpPasswordField(
                    controller: _passwordController,
                    obscure: _obscurePassword,
                    onToggle: () =>
                        setState(() => _obscurePassword = !_obscurePassword),
                    validator: (v) {
                      if (v == null || v.isEmpty) {
                        return 'Please enter a password';
                      }
                      if (v.length < 8) {
                        return 'Minimum 8 characters';
                      }
                      return null;
                    },
                  ),
                  const SizedBox(height: 8),
                  const SignUpHelperText('Minimum 8 characters.'),
                  const SizedBox(height: 24),

                  // Already have account link
                  Center(
                    child: GestureDetector(
                      onTap: () => context.go('/signin'),
                      child: Text(
                        'Already have an account? Sign In',
                        style: GoogleFonts.instrumentSans(
                          fontSize: 14,
                          fontWeight: FontWeight.w500,
                          color: Colors.black.withValues(alpha: 0.7),
                          height: 22 / 14,
                        ),
                      ),
                    ),
                  ),
                ],
              ),
            ),
          ),
        ),

        // Button
        Padding(
          padding: const EdgeInsets.fromLTRB(16, 16, 16, 16),
          child: SignUpPrimaryButton(
            label: 'Create Account',
            onTap: _handleCreateAccount,
            isLoading: _isLoading,
          ),
        ),
      ],
    );
  }
}

import 'package:flutter/foundation.dart';
import 'package:supabase_flutter/supabase_flutter.dart';
import 'models/vehicle_model.dart';

class VehiclesRepository {
  SupabaseClient get _client => Supabase.instance.client;
  Future<List<VehicleModel>> getUserVehicles({String? profileId}) async {
    final activeProfileId = profileId ?? _client.auth.currentUser?.id;
    if (activeProfileId == null) return [];
    try {
      final response = await _client
          .from('vehicles')
          .select()
          .eq('profile_id', activeProfileId)
          .order('created_at', ascending: false);
      final data = response as List<dynamic>;
      return data
          .map((e) => VehicleModel.fromJson(e as Map<String, dynamic>))
          .toList();
    } catch (e) {
      debugPrint('Error fetching vehicles: $e');
      rethrow;
    }
  }

  Future<VehicleModel> createVehicle({
    required String make,
    required String model,
    int? year,
    String? licensePlate,
    String? vin,
  }) async {
    final user = _client.auth.currentUser;
    final session = _client.auth.currentSession;
    if (user == null) throw Exception('User not authenticated');
    if (session == null) {
      throw Exception(
        'No active session. Please verify your email and sign in again.',
      );
    }
    final payload = <String, dynamic>{
      'profile_id': user.id,
      'make': make,
      'model': model,
      if (year != null) 'year': year,
      if (licensePlate != null && licensePlate.isNotEmpty)
        'license_plate': licensePlate,
      if (vin != null && vin.isNotEmpty) 'vin': vin,
    };
    try {
      final response = await _client
          .from('vehicles')
          .insert(payload)
          .select()
          .single();
      return VehicleModel.fromJson(response);
    } catch (e) {
      debugPrint('Error creating vehicle: $e');
      rethrow;
    }
  }

  Future<VehicleModel> updateVehicle({
    required int vehicleId,
    required String make,
    required String model,
    int? year,
    String? licensePlate,
    String? vin,
  }) async {
    final user = _client.auth.currentUser;
    if (user == null) throw Exception('User not authenticated');
    final payload = <String, dynamic>{
      'make': make,
      'model': model,
      'year': year,
      'license_plate': licensePlate,
      'vin': vin,
    };
    try {
      final response = await _client
          .from('vehicles')
          .update(payload)
          .eq('id', vehicleId)
          .eq('profile_id', user.id)
          .select()
          .single();
      return VehicleModel.fromJson(response);
    } catch (e) {
      debugPrint('Error updating vehicle: $e');
      rethrow;
    }
  }

  Future<void> deleteVehicle(int vehicleId) async {
    final user = _client.auth.currentUser;
    if (user == null) throw Exception('User not authenticated');
    try {
      await _client
          .from('vehicles')
          .delete()
          .eq('id', vehicleId)
          .eq('profile_id', user.id);
    } catch (e) {
      debugPrint('Error deleting vehicle: $e');
      rethrow;
    }
  }
}

