    try {
      final response = await _client
          .from('vehicles')
          .select()
          .eq('profile_id', activeProfileId)
          .order('created_at', ascending: false);
      final data = response as List<dynamic>;
      return data
          .map((e) => VehicleModel.fromJson(e as Map<String, dynamic>))
